1936→    List<LocalMessage> collectMessagesInThreads(Account account, List<LocalMessage> messages)
1937→            throws MessagingException {
1938→
1939→        LocalStore localStore = localStoreProvider.getInstance(account);
1940→
1941→        List<LocalMessage> messagesInThreads = new ArrayList<>();
1942→        for (LocalMessage localMessage : messages) {
1943→            long rootId = localMessage.getRootId();
1944→            long threadId = (rootId == -1) ? localMessage.getThreadId() : rootId;
1945→
1946→            List<LocalMessage> messagesInThread = localStore.getMessagesInThread(threadId);
1947→
1948→            messagesInThreads.addAll(messagesInThread);
1949→        }
1950→
1951→        return messagesInThreads;
1952→    }
