887→    @VisibleForTesting
888→    void processPendingMoveOrCopy(Account account, long srcFolderId, long destFolderId, List<String> uids,
889→                                  MoveOrCopyFlavor operation, Map<String, String> newUidMap) throws MessagingException {
890→        requireNotNull(newUidMap);
891→
892→        LocalStore localStore = localStoreProvider.getInstance(account);
893→
894→        LocalFolder localSourceFolder = localStore.getFolder(srcFolderId);
895→        localSourceFolder.open();
896→        String srcFolderServerId = localSourceFolder.getServerId();
897→
898→        LocalFolder localDestFolder = localStore.getFolder(destFolderId);
899→        localDestFolder.open();
900→        String destFolderServerId = localDestFolder.getServerId();
901→
902→        Backend backend = getBackend(account);
903→
904→        Map<String, String> remoteUidMap;
905→        switch (operation) {
906→            case COPY:
907→                remoteUidMap = backend.copyMessages(srcFolderServerId, destFolderServerId, uids);
908→                break;
909→            case MOVE:
910→                remoteUidMap = backend.moveMessages(srcFolderServerId, destFolderServerId, uids);
911→                break;
912→            case MOVE_AND_MARK_AS_READ:
913→                remoteUidMap = backend.moveMessagesAndMarkAsRead(srcFolderServerId, destFolderServerId, uids);
914→                break;
915→            default:
916→                throw new RuntimeException("Unsupported messaging operation");
917→        }
918→
919→        if (operation != MoveOrCopyFlavor.COPY) {
920→            destroyPlaceholderMessages(localSourceFolder, uids);
921→        }
922→
923→        // TODO: Change Backend interface to ensure we never receive null for remoteUidMap
924→        if (remoteUidMap == null) {
925→            remoteUidMap = Collections.emptyMap();
926→        }
927→
928→        // Update local messages (that currently have local UIDs) with new server IDs
929→        for (String uid : uids) {
930→            String localUid = newUidMap.get(uid);
931→            String newUid = remoteUidMap.get(uid);
932→
933→            LocalMessage localMessage = localDestFolder.getMessage(localUid);
934→            if (localMessage == null) {
935→                // Local message no longer exists
936→                continue;
937→            }
938→
939→            if (newUid != null) {
940→                // Update local message with new server ID
941→                localMessage.setUid(newUid);
942→                localDestFolder.changeUid(localMessage);
943→                for (MessagingListener l : getListeners()) {
944→                    l.messageUidChanged(account, destFolderId, localUid, newUid);
945→                }
946→            } else {
947→                // New server ID wasn't provided. Remove local message.
948→                localMessage.destroy();
949→            }
950→        }
951→    }
