24→public class PendingCommandSerializer {
25→    private static final PendingCommandSerializer INSTANCE = new PendingCommandSerializer();
26→
27→
28→    private final Map<String, JsonAdapter<? extends PendingCommand>> adapters;
29→
30→
31→    private PendingCommandSerializer() {
32→        Moshi moshi = new Moshi.Builder().build();
33→        HashMap<String, JsonAdapter<? extends PendingCommand>> adapters = new HashMap<>();
34→
35→        adapters.put(MessagingControllerCommands.COMMAND_MOVE_OR_COPY, moshi.adapter(PendingMoveOrCopy.class));
36→        adapters.put(MessagingControllerCommands.COMMAND_MOVE_AND_MARK_AS_READ,
37→                moshi.adapter(PendingMoveAndMarkAsRead.class));
38→        adapters.put(MessagingControllerCommands.COMMAND_APPEND, moshi.adapter(PendingAppend.class));
39→        adapters.put(MessagingControllerCommands.COMMAND_REPLACE, moshi.adapter(PendingReplace.class));
40→        adapters.put(MessagingControllerCommands.COMMAND_EMPTY_TRASH, moshi.adapter(PendingEmptyTrash.class));
41→        adapters.put(MessagingControllerCommands.COMMAND_EXPUNGE, moshi.adapter(PendingExpunge.class));
42→        adapters.put(MessagingControllerCommands.COMMAND_MARK_ALL_AS_READ, moshi.adapter(PendingMarkAllAsRead.class));
43→        adapters.put(MessagingControllerCommands.COMMAND_SET_FLAG, moshi.adapter(PendingSetFlag.class));
44→        adapters.put(MessagingControllerCommands.COMMAND_DELETE, moshi.adapter(PendingDelete.class));
45→
46→        this.adapters = Collections.unmodifiableMap(adapters);
47→    }
48→
49→
50→    public static PendingCommandSerializer getInstance() {
51→        return INSTANCE;
52→    }
53→
54→
55→    public <T extends PendingCommand> String serialize(T command) {
56→        // noinspection unchecked, we know the map has correctly matching adapters
57→        JsonAdapter<T> adapter = (JsonAdapter<T>) adapters.get(command.getCommandName());
58→        if (adapter == null) {
59→            throw new IllegalArgumentException("Unsupported pending command type!");
60→        }
61→        return adapter.toJson(command);
62→    }
63→
64→    public PendingCommand unserialize(long databaseId, String commandName, String data) {
65→        JsonAdapter<? extends PendingCommand> adapter = adapters.get(commandName);
66→        if (adapter == null) {
67→            throw new IllegalArgumentException("Unsupported pending command type!");
68→        }
69→        try {
70→            PendingCommand command = adapter.fromJson(data);
71→            command.databaseId = databaseId;
72→            return command;
73→        } catch (IOException e) {
74→            throw new IOError(e);
75→        }
76→    }
77→}
